mapper.select:
select id, warehouse_id, upstream_task_id, task_type, status, priority, payload_json, created_at, updated_at
from wcs_task
where warehouse_id = #{warehouseId}
  and id = #{id}

select id, warehouse_id, upstream_task_id, task_type, status, priority, payload_json, created_at, updated_at
from wcs_task
where warehouse_id = #{warehouseId}
  and business_key = #{businessKey}

mapper.update:
update wcs_task
set status = #{status},
    updated_at = now()
where warehouse_id = #{warehouseId}
  and id = #{id}
